/**
 * Acquired Sandbox - single-file, zero-dependency server (for hosting).
 * The entire web UI is embedded below; only Node.js built-ins are used.
 */
const http=require('http');
const crypto=require('crypto');

const cfg=(k,d)=> (process.env[k]!==undefined && process.env[k]!=='') ? process.env[k] : d;
const PORT=Number(cfg('PORT','3000'));
const ENV=(cfg('ACQUIRED_ENV','test')).toLowerCase();
const API_BASE=ENV==='production'?'https://api.acquired.com/v1':'https://test-api.acquired.com/v1';
const PAY_BASE=ENV==='production'?'https://pay.acquired.com/v1':'https://test-pay.acquired.com/v1';
const APP_ID=cfg('ACQUIRED_APP_ID','');
const APP_KEY=cfg('ACQUIRED_APP_KEY','');
const SIGNING_KEY=cfg('ACQUIRED_SIGNING_KEY','');
const PUBLIC_KEY=cfg('ACQUIRED_PUBLIC_KEY','');
const DEFAULT_COMPANY_ID=cfg('ACQUIRED_COMPANY_ID','');
const DEFAULT_MID=cfg('ACQUIRED_MID','');
const ACCESS_PASSWORD=cfg('ACCESS_PASSWORD','');

const INDEX_HTML=Buffer.from("",'base64').toString('utf8');

if(typeof fetch!=='function'){console.error('Node 18+ required');process.exit(1);}

let tokenCache={token:null,expiresAt:0};
async function getToken(force){
  const now=Date.now();
  if(!force&&tokenCache.token&&now<tokenCache.expiresAt-30000)return tokenCache.token;
  if(!APP_ID||!APP_KEY)throw new Error('Missing ACQUIRED_APP_ID or ACQUIRED_APP_KEY (set them as environment variables).');
  const res=await fetch(API_BASE+'/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({app_id:APP_ID,app_key:APP_KEY})});
  const data=await res.json().catch(()=>({}));
  if(!res.ok||!data.access_token){const e=new Error(data.title||'Login failed - check your App ID and App Key.');e.detail=data;throw e;}
  tokenCache={token:data.access_token,expiresAt:now+(data.expires_in||3600)*1000};
  return tokenCache.token;
}

const webhookLog=[];const MAX=200;
function verifyHash(raw,hdr){
  if(!SIGNING_KEY)return{checked:false,valid:null,note:'No signing key configured.'};
  if(!hdr)return{checked:true,valid:false,note:'No Hash header on this webhook.'};
  const provided=String(hdr).split(',').map(h=>h.trim().toLowerCase());
  const cand=new Set([raw,raw.replace(/\s+/g,'')]);
  try{cand.add(JSON.stringify(JSON.parse(raw)));}catch(_){}
  for(const c of cand){const h=crypto.createHmac('sha256',SIGNING_KEY).update(c,'utf8').digest('hex').toLowerCase();if(provided.includes(h))return{checked:true,valid:true,computed:h,note:'Signature matches.'};}
  const h=crypto.createHmac('sha256',SIGNING_KEY).update(raw,'utf8').digest('hex').toLowerCase();
  return{checked:true,valid:false,computed:h,provided,note:'No candidate hash matched the Hash header.'};
}
function send(res,s,o){const b=JSON.stringify(o);res.writeHead(s,{'Content-Type':'application/json'});res.end(b);}
function readBody(req){return new Promise(r=>{let d='';req.on('data',c=>{d+=c;if(d.length>4e6)req.destroy();});req.on('end',()=>r(d));req.on('error',()=>r(d));});}

const server=http.createServer(async(req,res)=>{
  const url=req.url||'/';const method=req.method||'GET';
  if(ACCESS_PASSWORD){
    const exp='Basic '+Buffer.from('acquired:'+ACCESS_PASSWORD).toString('base64');
    if((req.headers['authorization']||'')!==exp){res.writeHead(401,{'WWW-Authenticate':'Basic realm="Acquired Sandbox"','Content-Type':'text/plain'});return res.end('Password required');}
  }
  try{
    if(url==='/api/config'&&method==='GET')return send(res,200,{env:ENV,api_base:API_BASE,pay_base:PAY_BASE,app_id:APP_ID,public_key:PUBLIC_KEY,company_id:DEFAULT_COMPANY_ID,mid:DEFAULT_MID,has_app_key:Boolean(APP_KEY),has_signing_key:Boolean(SIGNING_KEY)});
    if(url==='/api/test-connection'&&method==='GET'){try{await getToken(true);return send(res,200,{ok:true,message:'Connected. Access token obtained successfully.'});}catch(e){return send(res,502,{ok:false,message:e.message,detail:e.detail||null});}}
    if(url==='/api/proxy'&&method==='POST'){
      const body=JSON.parse((await readBody(req))||'{}');
      const {method:m='GET',path:apiPath,body:reqBody,company_id,mid}=body;
      if(!apiPath||!apiPath.startsWith('/'))return send(res,400,{error:'A "path" starting with "/" is required.'});
      let token;try{token=await getToken();}catch(e){return send(res,502,{error:e.message,detail:e.detail||null,stage:'login'});}
      const headers={Authorization:'Bearer '+token,'Content-Type':'application/json'};
      const c=company_id||DEFAULT_COMPANY_ID,mi=mid||DEFAULT_MID;
      if(c)headers['Company-Id']=c;if(mi)headers['Mid']=mi;
      const up={method:String(m).toUpperCase(),headers};
      if(!['GET','HEAD'].includes(up.method)&&reqBody!=null)up.body=JSON.stringify(reqBody);
      const sent={method:up.method,url:API_BASE+apiPath,headers:{...headers,Authorization:'Bearer <access_token>'},body:up.body?JSON.parse(up.body):undefined};
      try{const u=await fetch(API_BASE+apiPath,up);const t=await u.text();let data;try{data=t?JSON.parse(t):null;}catch{data=t;}return send(res,200,{ok:u.ok,status:u.status,statusText:u.statusText,data,sent});}catch(e){return send(res,502,{error:e.message,sent,stage:'upstream'});}
    }
    if(url==='/api/webhooks/incoming'&&method==='POST'){
      const raw=await readBody(req);const hdr=req.headers['hash']||'';const verification=verifyHash(raw,hdr);
      let p;try{p=JSON.parse(raw);}catch{p=null;}
      webhookLog.push({id:crypto.randomUUID(),receivedAt:new Date().toISOString(),headers:{'Company-Id':req.headers['company-id']||null,'Mid':req.headers['mid']||null,'Webhook-Version':req.headers['webhook-version']||null,'Hash':hdr||null,'Content-Type':req.headers['content-type']||null},webhook_type:p&&p.webhook_type?p.webhook_type:'unknown',body:p,raw,verification});
      if(webhookLog.length>MAX)webhookLog.shift();
      return send(res,200,{received:true});
    }
    if(url==='/api/webhooks'&&method==='GET')return send(res,200,{webhooks:[...webhookLog].reverse(),signing_key_configured:Boolean(SIGNING_KEY)});
    if(url==='/api/webhooks/clear'&&method==='POST'){webhookLog.length=0;return send(res,200,{ok:true});}
    if(url==='/api/webhooks/simulate'&&method==='POST'){
      const inB=JSON.parse((await readBody(req))||'{}');const b=inB&&inB.body?inB.body:inB;const raw=JSON.stringify(b);
      const hash=SIGNING_KEY?crypto.createHmac('sha256',SIGNING_KEY).update(raw,'utf8').digest('hex'):'';
      const rec={id:crypto.randomUUID(),receivedAt:new Date().toISOString(),headers:{'Webhook-Version':'2','Hash':hash||null,'Content-Type':'application/json',simulated:true},webhook_type:b&&b.webhook_type?b.webhook_type:'unknown',body:b,raw,verification:verifyHash(raw,hash),simulated:true};
      webhookLog.push(rec);if(webhookLog.length>MAX)webhookLog.shift();
      return send(res,200,{ok:true,record:rec});
    }
    if(url.startsWith('/api/'))return send(res,404,{error:'Unknown endpoint'});
    res.writeHead(200,{'Content-Type':'text/html; charset=utf-8'});return res.end(INDEX_HTML);
  }catch(e){return send(res,500,{error:e.message});}
});
server.listen(PORT,()=>{console.log('Acquired Sandbox running on port '+PORT+' ('+ENV+')');});
